.darma-loader-darma-custom-070 {
  display: inline-grid;
  width: 90px;
  aspect-ratio: 1;
  clip-path: polygon(100% 50%,85.36% 85.36%,50% 100%,14.64% 85.36%,0% 50%,14.64% 14.64%,50% 0%,85.36% 14.64%);
  background: var(--loader-color, #574951);
  animation: darma-loader-darma-custom-070-l2 6s infinite linear;
}
.darma-loader-darma-custom-070:before,
.darma-loader-darma-custom-070:after {
  content:"";
  grid-area: 1/1;
  background: var(--loader-secondary-color, #83988e);
  clip-path: polygon(100% 50%,81.17% 89.09%,38.87% 98.75%,4.95% 71.69%,4.95% 28.31%,38.87% 1.25%,81.17% 10.91%);
  margin: 10%;
  animation: inherit;
  animation-duration: 10s;
}
.darma-loader-darma-custom-070:after {
  background: #BCDEA5;
  clip-path: polygon(100% 50%,75% 93.3%,25% 93.3%,0% 50%,25% 6.7%,75% 6.7%);
  margin: 20%;
  animation-duration: 3s;
  animation-direction: reverse;
}
@keyframes darma-loader-darma-custom-070-l2 {to{rotate: 1turn}}

